route {
    if (is_method("INVITE") && !has_totag()) {
        if (!check_concurrent("$fU")) {
            xlog("L_WARN", "$fU over limit: $var(concurrent_count)/$var(concurrent_limit)\n");
            sl_send_reply(486, "Too Many Calls");
            exit;
        }
    }
}
...

